import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './ProposalsList.css';

function ProposalsList() {
  const [proposals, setProposals] = useState([]);
  const [filter, setFilter] = useState('all');
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProposals();
  }, []);

  const fetchProposals = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://127.0.0.1:8000/api/proposals/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProposals(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching proposals:', error);
      setLoading(false);
    }
  };

  const handleAccept = async (id) => {
    try {
      const token = localStorage.getItem('access');
      await axios.patch(`http://127.0.0.1:8000/api/proposals/${id}/`, 
        { status: 'accepted' },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      fetchProposals();
    } catch (error) {
      console.error('Error accepting proposal:', error);
    }
  };

  const handleReject = async (id) => {
    try {
      const token = localStorage.getItem('access');
      await axios.patch(`http://127.0.0.1:8000/api/proposals/${id}/`, 
        { status: 'rejected' },
        { headers: { Authorization: `Bearer ${token}` } }
      );
      fetchProposals();
    } catch (error) {
      console.error('Error rejecting proposal:', error);
    }
  };

  const filteredProposals = filter === 'all' 
    ? proposals 
    : proposals.filter(p => p.status === filter);

  const getStatusColor = (status) => {
    switch(status) {
      case 'pending': return '#ffc107';
      case 'accepted': return '#28a745';
      case 'rejected': return '#dc3545';
      default: return '#6c757d';
    }
  };

  if (loading) return <div className="loading">Loading proposals...</div>;

  return (
    <div className="proposals-container">
      <h2>Proposals</h2>
      
      <div className="filter-bar">
        <select value={filter} onChange={(e) => setFilter(e.target.value)}>
          <option value="all">All Proposals</option>
          <option value="pending">Pending</option>
          <option value="accepted">Accepted</option>
          <option value="rejected">Rejected</option>
        </select>
      </div>

      <div className="proposals-list">
        {filteredProposals.length > 0 ? (
          filteredProposals.map(proposal => (
            <div key={proposal.id} className="proposal-card">
              <div className="proposal-header">
                <h3>{proposal.project_title}</h3>
                <span className="status" style={{ backgroundColor: getStatusColor(proposal.status) }}>
                  {proposal.status}
                </span>
              </div>
              
              <div className="proposal-details">
                <p><strong>Freelancer:</strong> {proposal.freelancer_name}</p>
                <p><strong>Bid Amount:</strong> ₹{proposal.bid_amount}</p>
                <p><strong>Duration:</strong> {proposal.estimated_days} days</p>
                <p><strong>Cover Letter:</strong> {proposal.cover_letter}</p>
              </div>

              {proposal.status === 'pending' && (
                <div className="proposal-actions">
                  <button onClick={() => handleAccept(proposal.id)} className="accept-btn">Accept</button>
                  <button onClick={() => handleReject(proposal.id)} className="reject-btn">Reject</button>
                </div>
              )}
            </div>
          ))
        ) : (
          <p className="no-proposals">No proposals found</p>
        )}
      </div>
    </div>
  );
}

export default ProposalsList;
